import 'package:flutter/material.dart';import '../core/app_colors/app_colors.dart';class AppTextField extends StatefulWidget {  const AppTextField({    super.key,    this.hintText = '',    this.secure = false,    this.controller,    this.onChanged,    this.validator,  });  final String hintText;  final bool secure;  final TextEditingController? controller;  final ValueChanged<String>? onChanged;  final String? Function(String?)? validator;  @override  State<AppTextField> createState() => _AppTextFieldState();}class _AppTextFieldState extends State<AppTextField> {  late bool _secured;  @override  void initState() {    super.initState();    _secured = widget.secure;  }  void _toggleVisibility() {    setState(() {      _secured = !_secured;    });  }  @override  Widget build(BuildContext context) {    final borderRadius = BorderRadius.circular(16);    final borderSide = BorderSide(      color: AppColors.gray.withValues(alpha: 0.85),      width: 1,    );    return TextFormField(      controller: widget.controller,      onChanged: widget.onChanged,      validator: widget.validator,      obscureText: _secured,      cursorColor: AppColors.gray.withValues(alpha: 0.85),      decoration: InputDecoration(        hintText: widget.hintText,        hintStyle: const TextStyle(          fontSize: 16,          fontWeight: FontWeight.w400,          color: AppColors.gray,        ),        filled: true,        fillColor: AppColors.textFormFieldBackground.withValues(alpha: 0.47),        focusedBorder: OutlineInputBorder(          borderRadius: borderRadius,          borderSide: borderSide,        ),        enabledBorder: OutlineInputBorder(          borderRadius: borderRadius,          borderSide: borderSide,        ),        border: OutlineInputBorder(          borderRadius: borderRadius,          borderSide: borderSide,        ),        suffixIcon: widget.secure            ? InkWell(          onTap: _toggleVisibility,          splashColor: Colors.transparent,          child: Icon(            _secured ? Icons.visibility_off : Icons.visibility,            color: AppColors.gray.withValues(alpha: 0.85),          ),        )            : null,      ),    );  }}